const estacao = $input.item.json.estacao;
const ano = $input.item.json.ano;
const primeiroDia = parseInt($input.item.json.primeiro_dia);
const ultimoDia = parseInt($input.item.json.ultimo_dia);

const linksParaBaixar = [];

for (let dia = primeiroDia; dia <= ultimoDia; dia++) {
  const diaFormatado = String(dia).padStart(3, '0');
  const nomeArquivo = `${estacao}${diaFormatado}1.zip`;
  const url = `https://geoftp.ibge.gov.br/informacoes_sobre_posicionamento_geodesico/rbmc/dados/${ano}/${diaFormatado}/${nomeArquivo}`;

  linksParaBaixar.push({
    json: {
      url_download: url,
      estacao: estacao,
      ano: ano,
      dia_corrido: diaFormatado
    }
  });
}

return linksParaBaixar;

let results = [];

for (item of items) {
    for (key of Object.keys(item.binary)) {
        results.push({
            json: {
                fileName: item.binary[key].fileName,
                url_download: $('Loop Over Items').item.json.url_download,
                estacao: $('Loop Over Items').item.json.estacao,
                ano: $('Loop Over Items').item.json.ano
            },
            binary: {
                data: item.binary[key],
            }
        });
    }
}

return results;

const resposta = Array.isArray($input.item.json) ? $input.item.json[0] : $input.item.json;
const resumo = resposta.resumo ?? {};
const url_download = $('Loop Over Items').item.json.url_download;

const s = (v) => (v ?? '').toString().trim();

const parseDataIBGE = (str) => {
  if (!str) return null;
  try {
    return str.replace(/\//g, '-').replace(' ', 'T');
  } catch(e) { return null; }
};

return [{
  json: {
    url_download,
    link_zip: s(resposta.link),
    status_ppp: s(resposta.status),
    processo_em: parseDataIBGE(s(resumo.PROCES)),
    rinex: s(resumo.RINEX),
    marco: s(resumo.MARCO),
    inicio: s(resumo.INICIO),
    fim: s(resumo.FIM),
    modo: s(resumo.MODO),
    antena: s(resumo.ANTENA),
    altant: s(resumo.ALTANT),
    intervalo: s(resumo.INTERV),
    frequencia: s(resumo.FREQ),
    observacao: s(resumo.OBSERV),
    orbita: s(resumo.ORBITA),
    datum: s(resumo.DATUM),
    lat: s(resumo.LAT),
    lon: s(resumo.LON),
    hgeo: s(resumo.HGEO),
    sigma_lat: s(resumo.SLAT),
    sigma_lon: s(resumo.SLON),
    sigma_hgeo: s(resumo.SHGEO),
    utmn: s(resumo.UTMN),
    utme: s(resumo.UTME),
    mc: s(resumo.MC),
    modelo_geoidal: s(resumo.MODELO),
    fator_correcao: s(resumo.FATCOR),
    incerteza: s(resumo.INCERT),
    hnor: s(resumo.HNOR)
  }
}];

let results = [];

for (item of items) {
    for (key of Object.keys(item.binary)) {
        results.push({
            json: {
                fileName: item.binary[key].fileName,
                url_download: $('Loop Over Items').item.json.url_download
            },
            binary: {
                data: item.binary[key],
            }
        });
    }
}

return results;

