const sql = $input.item.json.output.trim();

if (sql === 'FORA_DO_ESCOPO') {
  throw new Error('FORA_DO_ESCOPO');
}

const proibido = /insert|update|delete|drop|alter|truncate|create|grant|revoke/i;
if (proibido.test(sql)) {
  throw new Error('SQL_INVALIDO');
}

if (!/limit\s+\d+/i.test(sql)) {
  return [{ json: { sql: sql.replace(/;?\s*$/, '') + ' LIMIT 500;' } }];
}

return [{ json: { sql } }];
